async def hyde_embed(query: str, model: str = "gpt-4o-mini") -> list[float]:
    """Generate a hypothetical answer and embed it instead of the raw query."""
    resp = await client.chat.completions.create(
        model=model,
        temperature=0.0,
        max_tokens=150,
        messages=[
            {
                "role": "system",
                "content": (
                    "Write a short, factual answer to the question as if you were "
                    "reading it from a company wiki. Be concise. "
                    "If you don't know the answer, describe what such a document would say."
                ),
            },
            {"role": "user", "content": query},
        ],
    )
    hypothetical_answer = resp.choices[0].message.content
    return embed(hypothetical_answer)

async def step_back_query(query: str, model: str = "gpt-4o-mini") -> str:
    """Generalize the query to a higher-level concept for better retrieval."""
    resp = await client.chat.completions.create(
        model=model,
        temperature=0.0,
        max_tokens=60,
        messages=[
            {
                "role": "system",
                "content": (
                    "Rewrite the question as a broader, more general search query "
                    "that would find the relevant policy or documentation. "
                    "Return only the rewritten query, nothing else."
                ),
            },
            {"role": "user", "content": query},
        ],
    )
    return resp.choices[0].message.content.strip()

from dataclasses import dataclass

@dataclass
class CitedAnswer:
    answer: str
    sources: list[dict]  # [{title, url, updated_at, snippet}]

def build_rag_prompt(query: str, chunks: list[Chunk]) -> list[dict]:
    context_parts = []
    for i, chunk in enumerate(chunks):
        age_note = ""
        days_old = (datetime.utcnow() - chunk.updated_at).days
        if days_old > 90:
            age_note = f" [Note: last updated {days_old} days ago — verify if current]"
        context_parts.append(
            f"[{i+1}] {chunk.title} ({chunk.source}){age_note}\n{chunk.text}"
        )
    context = "\n\n".join(context_parts)

    return [
        {
            "role": "system",
            "content": (
                "You are a company knowledge assistant. Answer using only the provided documents. "
                "Cite sources inline as [1], [2], etc. matching the document numbers. "
                "If the documents don't contain the answer, say so explicitly — do not guess. "
                "If a source is marked as possibly outdated, note that in your answer."
            ),
        },
        {
            "role": "user",
            "content": f"Documents:\n{context}\n\nQuestion: {query}",
        },
    ]

async def rag_answer(query: str, chunks: list[Chunk]) -> CitedAnswer:
    resp = await client.chat.completions.create(
        model="gpt-4o-mini",
        temperature=0.1,
        messages=build_rag_prompt(query, chunks),
    )
    answer_text = resp.choices[0].message.content
    sources = [
        {
            "index": i + 1,
            "title": c.title,
            "url": c.url,
            "updated_at": c.updated_at.isoformat(),
            "snippet": c.text[:200],
        }
        for i, c in enumerate(chunks)
    ]
    return CitedAnswer(answer=answer_text, sources=sources)
